import Dispute from '@models/dispute/Dispute'; // Alias import
import logger from '@utils/logger'; // Alias import

export const submitVote = async (data: { disputeId: string; userId: string; voteType: string }): Promise<any> => {
  const dispute = await Dispute.findById(data.disputeId);
  if (!dispute) {
    throw new Error('Dispute not found');
  }

  dispute.votes = dispute.votes || [];
  dispute.votes.push({ userId: data.userId, voteType: data.voteType, timestamp: new Date() });
  await dispute.save();

  logger.info('Vote recorded in service', { disputeId: data.disputeId, userId: data.userId });
  return { updated: true };
};
